var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"으으… 근육통이….","JPN":"うう……筋肉痛が……","ENG":"Ugh... Muscles cramps...","TWN":"唔…肌肉酸痛…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"성녀는 체력이 많이 부족한 것 같습니다.","JPN":"聖女は体力がだいぶ足りないようですね。","ENG":"You seem to lack a good deal of stamina.","TWN":"聖女體力真差。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"지팡이의 힘에 기대는 것은 바람직한 행위가 아닙니다, 루크레시아.","JPN":"杖の力に依存することは望ましい行為ではありません、ルクレシア。","ENG":"You mustn't always rely on the power of your staff, Lucrecia.","TWN":"還要拄著杖，這樣就不是完全靠自己的力量，露可蕾西亞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 이상한 겁니다. 가파른 산을 뛰어다녔는데 그리 멀쩡하다니요.","JPN":"あなたがおかしいのです。険しい山を走り回ったのに何ともないなんて。","ENG":"I'm not the one who's weird. How are you still so tireless, after all that trekking?","TWN":"你才奇怪，跑上這麼陡的山，居然還這麼有精神。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"깃발까지 들고 어떻게 그럴 수가 있는 건가요?","JPN":"旗まで持っているのに、どうしてそんなことが可能なのですか？","ENG":"You've even been holding the banner up.","TWN":"而且還拿著旗幟，這怎麼可能？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"확실히 오늘은 몸상태가 좋은 편이군요.","JPN":"確かに、今日は体の具合がいい方ですね。","ENG":"I do feel quite spirited today.","TWN":"今天的狀態的確很好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"방금 전 싸움에서도 구원자보다 더 많은 괴수를 쓰러트렸을 정도입니다.","JPN":"先ほどの戦いでも、救世主より多くの怪獣を倒したくらいです。","ENG":"I even vanquished more monsters than the Savior in the fight earlier.","TWN":"在剛才的戰鬥中，我擊殺的怪獸數量還比救贖者大人大人多呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯 님이요?","JPN":"シャーロット様が？","ENG":"You did, Carlota?","TWN":"真的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"네. 제가 스물 여섯 마리의 괴수를 해치운 반면, 구원자는 스물 두 마리의 괴수만을 해치웠습니다.","JPN":"はい。私は26匹の怪獣を倒しましたが、救世主は22匹でした。","ENG":"Indeed. I eliminated 26 monsters, while the Savior only eliminated 22.","TWN":"真的。我一共擊殺26隻怪獸，救贖者大人大人只擊殺22隻。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자 또한 자신의 패배를 인정했고요.","JPN":"救世主も自分の負けを認めました。","ENG":"The Savior has also admitted his defeat.","TWN":"救贖者大人大人也有承認自己的失敗。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이상하네요. 구원자 님 방향으로 어림잡아 오십은 갔을 텐데요.","JPN":"おかしいですね。救世主様の方向にざっと50匹は向かっていたはずですけど。","ENG":"Odd. I saw around 50 go toward the Savior.","TWN":"真奇怪，照我看到的，救贖者大人大人應該至少擊殺50隻才對。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"날 속였군. 구원자.","JPN":"私を騙したな、救世主。","ENG":"The Savior fooled me.","TWN":"你騙我，救贖者大人大人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"매번 구원자님께 깨져 놓고 잘도 이겼다는 생각을 하셨군요.","JPN":"毎回救世主様に負けておいて、よく勝ったと思えましたね。","ENG":"He always beats you. Why did you think it would be different this time?","TWN":"你每次都輸給救贖者大人大人，怎麼還會覺得自己有可能贏？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나 축제. 인가요….","JPN":"それより、お祭り、ですか……","ENG":"Anyway, about the festival...","TWN":"說到慶典…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"신기한 풍습입니다. 순정한 남녀 한 쌍을 선별해 풍요를 권장하는 신께 춤을 올린다니.","JPN":"不思議な風習です。無垢な男女を選抜し、豊穣を司る神に踊りを捧げるとは。","ENG":"It's an interesting tradition, to say the least. Selecting a chaste couple to dance for the god of prosperity.","TWN":"還真是特別的習俗。選出一對純真的男女，向神跳豐收舞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님은 사람이 너무 좋으십니다. 직접 나서실 필요까지는 없는 일이었어요.","JPN":"救世主様は人が良すぎます。自らがされる必要などありませんのに。","ENG":"The Savior can be too kind-hearted sometimes. He didn't have to step in.","TWN":"救贖者大人大人人真的太好，根本不需要他親自出馬的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자가 신경 쓰이십니까?","JPN":"救世主が気になりますか？","ENG":"Does the Savior concern you?","TWN":"你是在擔心救贖者大人大人嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저는 그 분의 성녀입니다. 구원자님의 안위를 걱정하는 건 당연한 일이지요.","JPN":"私はあの方の聖女です。救世主様の安危を心配するのは、当たり前のことです。","ENG":"I am his Saintess. It is natural that I worry about the Savior's safety.","TWN":"我是他的聖女，擔心救贖者大人大人的安危是理所當然的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면 루크레시아가 선별되면 그만인 문제입니다.","JPN":"それなら、ルクレシアが選ばれればいいのです。","ENG":"Well, then I guess you can save your concerns by getting selected as his partner.","TWN":"那要是露可蕾西亞被選中，這就不是個問題。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"자신 없으십니까?","JPN":"自信がないのですか？","ENG":"Or do you think you will not be chosen?","TWN":"你沒信心嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"매년 <color=#ffd34c>순정</color>한 남녀 한 쌍을 뽑아, 마을의 풍요를 기원하기 위해 신께 제를 올리는 것입니다.","JPN":"毎年、<color=#ffd34c>無垢</color>な男女を選抜し、村の豊穣を祈りながら祭祀を行うのです。","ENG":"We select a <color=#ffd34c>chaste</color> couple to perform a rite, praying to the gods for the prosperity of the village.","TWN":"每年選出一對<color=#ffd34c>純真的</color>男女，向神祈求村莊的豐收。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>불순한 마음</color>으로 순정을 자처하는 꼴이 퍽이나 우습다만.","JPN":"<color=#ffd34c>不純な心</color>で無垢を自称する様はなかなか面白いが。","ENG":"It certainly is amusing how you claim to be chaste while harboring such <color=#ffd34c>impure thoughts</color>.","TWN":"<color=#ffd34c>明明有一顆黑心</color>，卻裝得很純情的樣子，真是好笑。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"유감이군, 루크레시아. 네 알량한 바람을 이루기에는 조금 <color=#ffd34c>늦은 것 같구나</color>.","JPN":"残念だったな、ルクレシア。貴様のつまらない願いを叶えるには少々<color=#ffd34c>遅かったようだ</color>。","ENG":"However, Lucrecia, it seems you are <color=#ffd34c>too late</color> to fulfill your trifling desires.","TWN":"真是可惜， 露可蕾西亞，你卑微的心願<color=#ffd34c>這麼晚才實現</color>。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"우문이로군요. 제국의 성녀가 고작 변방마을의 일을 신경쓰다니요.","JPN":"愚問ですね。帝国の聖女が、たかが辺境の村のことを気にするなんて。","ENG":"A pointless question. As the Saintess of the Empire, there is no need for me to dwell on the matters of a remote village.","TWN":"真是愚蠢的問題。帝國的聖女才不會擔心偏遠村莊的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"사제들로부터 교양을 익힌 몸입니다. 이곳 주민들을 상대로 제가 질 일은 없어요.","JPN":"司祭から教養を教わった身です。ここの住民を相手に私が負けるわけがありません。","ENG":"I've been taught conventional culture by other saints. I will not lose to the villagers here.","TWN":"我可是受過祭司們的訓練，怎麼可能會輸給這裡的居民。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하께서는 절 조롱하고 싶으신 모양입니다만…….","JPN":"殿下は私のことをからかいたいようですが……","ENG":"I imagine His Highness is attempting to mock me, but...","TWN":"雖然殿下根本是想戲弄我……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하에 대한 모욕은 사형입니다, 주의해주시길.","JPN":"殿下に対する侮辱は死刑です、ご注意を。","ENG":"Any insult toward His Highness is punishable by death. Choose your next words wisely.","TWN":"對殿下不敬是死罪，請注意。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당장 샬롯 님께서도 자원할 여성을 찾으러 마을을 돌아다녔을 텐데요.","JPN":"シャーロット様も志願する女性を探して村を歩き回られたではないですか。","ENG":"I assume you traversed around the village to find the women for the part, did you not?","TWN":"你現在不是應該去村裡尋找願意主持祭祀的女生嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하의 말씀대로 권위만을 앞세운 축제는 주민들의 풍습을 짓밟을 뿐입니다.","JPN":"殿下のおっしゃっていたとおり、権威だけを掲げた祭りは住民の風習を乱すだけです。","ENG":"As His Highness mentioned, a festival focused on authority will only trample on the villagers' traditions.","TWN":"殿下說，若是用權威來舉辦慶典，只會毀掉居民的習俗。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"성녀야 말로 아무런 흑심 없이 선별에 자처했다고 말할 수 있으십니까?","JPN":"聖女こそ、何の下心もなく選抜に出たと言えますか？","ENG":"And do you really think your intentions were pure when you applied for the role?","TWN":"聖女能說你在這個過程中完全沒有任何私心嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…말이 많으시군요. 전하나 샬롯 님께서는 잠자코 지켜보시면 됩니다.","JPN":"……うるさいですね。殿下とシャーロット様は黙って見ていてください。","ENG":"...You're quite the talker. Both you and His Highness can sit back and watch.","TWN":"…你話好多。你和殿下都靜觀其變吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"상황이 조금 틀어졌지만, 결국 변하는 것은 없을 테니 말이죠.","JPN":"状況は少し狂いましたけど、結局変わることは何もないはずですから。","ENG":"The situation is a little off the rails, but the outcome will remain the same.","TWN":"雖然情況有些變化，但終究不會改變什麼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"흐음. 오늘 이렇게 모여 주셔서 정말 감사합니다만….","JPN":"ふむ。本日はこのようにお集まりいただき、誠にありがたいのですが……","ENG":"Hmm. I am grateful for all of you gathering here today, but...","TWN":"咳咳，首先，謝謝大家一起聚在這裡…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"전하. 정말로 괜찮으시겠습니까?","JPN":"殿下。本当によろしいのですか。","ENG":"Your Highness, are you sure this is what you wish?","TWN":"殿下，這樣真的沒關係嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이 마을을 대표하는 건 자네가 아닌가.","JPN":"この村を代表するのはそなたではないか。","ENG":"You are the representative of this village.","TWN":"你才是這個村的村長不是嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"토착민들의 풍습을 따라가는데 번거로운 사족을 붙일 필요는 없겠지.","JPN":"土着民の風習に従うことに、なんの蛇足を加える必要があろうか。","ENG":"We are following the customs of the natives. I do not find the need to comment on it.","TWN":"遵循當地的習俗，不需要繁文縟節。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그럼, 전하의 말씀대로 이번 <color=#ffd34c>신의</color>의 선별은 작년과 동일한 방식으로 진행하겠습니다.","JPN":"それでは、殿下のおっしゃるとおり、今度の<color=#ffd34c>神衣</color>の選抜は去年と同じ方法で行います。","ENG":"Then, we will maintain the same method for selecting the woman to wear the <color=#ffd34c>sacred garments</color>.","TWN":"那麼，照殿下所言，今年<color=#ffd34c>聖衣</color>的選拔方法將與去年相同。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"방식은 간단합니다. 각자에게 드린 씨앗을 마지막까지 남기면 되는 것이지요.","JPN":"方法は簡単です。皆さんに渡した種を最後まで残すのです。","ENG":"The procedure is simple. Maintain the seed that was distributed to you until the very end.","TWN":"方法很簡單，每個人都會拿到種子，只要種子可以留到最後就獲選。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"씨앗? 남기라니… 그게 무슨 뜻이죠?","JPN":"種？　残すって……それはどういう意味ですか？","ENG":"\\"Maintain the seed?\\" …What is that supposed to mean?","TWN":"種子？留到最後…什麼意思？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"병이나 재해로 흉년이 들지 않기를 바라는 거래.","JPN":"病や災害で凶作にならないことを祈るんだって。","ENG":"I heard it was in hopes of avoiding a year of poor harvest.","TWN":"代表祈求沒有疾病或災害。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"마지막까지 남은 여성의 곡물을 매해 처음으로 땅에 심는다더라.","JPN":"最後まで残った女性の穀物を毎年最初に蒔くらしいよ。","ENG":"Whosever crop survives the longest is the one that they plant as the first official crop of the year.","TWN":"最後留下來種子，會首先栽種在土地裡。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님, 여긴 어떻게…?","JPN":"救世主様、どうしてここに……？","ENG":"Savior, why are you here...?","TWN":"救贖者大人大人，您怎麼會來…?"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안해, 루크레시아. 나 때문에 괜히 말려들게 한 것 같네.","JPN":"ごめん、ルクレシア。僕のせいで巻き込まれちゃったみたいだね。","ENG":"I'm sorry, Lucrecia. I guess you got tangled up in this because of me.","TWN":"對不起，露可蕾西亞。都是我連累你的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"설마 일이 이렇게까지 커질 줄은 몰랐어.","JPN":"まさかここまで大事になるとは思ってなかったよ。","ENG":"I didn't think this would become such a big deal.","TWN":"沒想到事情會發展到這樣。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"판을 벌리신 건 전하입니다. 구원자님께서 자책하실 필요는 없어요.","JPN":"大事にしたのは殿下です。救世主様がご自身を責める必要はありません。","ENG":"His Highness is the one who made matters worse. You mustn't blame yourself, Savior.","TWN":"設局的是殿下，救贖者大人大人無需自責。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그래도 내가 휘말리게 한 건 사실이니까. 오늘은 조금 도움을 주러 왔어.","JPN":"でも、僕が巻き込んだのは本当だから。今日はちょっと助けに来たんだ。","ENG":"Well, it's still true you're here because of me. I'm here to help you today.","TWN":"但你確實是因我受累，所以我今天是來幫你的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"도움이요…?","JPN":"助けに……？","ENG":"Help...?","TWN":"幫我…？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"응. 실은 어제 다른 분들이 하는 이야기를 들었거든.","JPN":"うん。実は、昨日他の人たちが話すのを聞いたんだ。","ENG":"Yes. I actually overheard a conversation between the others yesterday.","TWN":"嗯。其實我昨天有聽到其他人的對話。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"작년에는 꽤나 치열했던 모양이지만, 올해는 루크레시아가 있으니까.","JPN":"去年はかなり競争が激しかったようだけど、今年はルクレシアがいるから。","ENG":"The competition was fierce last year, but you're in the running this year.","TWN":"他們說，去年競爭很激烈，但今年有你在，"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"다들 냉정해지고 나니 루크레시아에게 양보하는 분위기로 넘어가더라.","JPN":"みんな冷静になってルクレシアに譲ろうって雰囲気になってた。","ENG":"After they calmed down, they were leaning toward giving the part to you.","TWN":"大家就變得很冷靜，說要把機會讓給你。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"성녀님이 제를 올리면, 분명 내년에는 풍년이 올 거라면서 말이야.","JPN":"聖女様が祭祀を行えば、きっと来年は豊作になるはずだってね。","ENG":"Saying that if the Saintess were to perform the rite, they would definitely reap a good harvest in the coming year.","TWN":"他們說，由聖女來主持祭祀，明年一定會是豐年。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"다른 분들이… 제게.","JPN":"他の人たちが……私に。","ENG":"The others said that... about me?","TWN":"大家…對我…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"걱정 마세요. 구원자님.","JPN":"心配しないでください。救世主様。","ENG":"Do not concern yourself with me, Savior.","TWN":"放心吧，救贖者大人大人。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 게 없더라도 저는 당대의 성녀이자 구원 기사단의 일원입니다.","JPN":"そのようなことがなくても、私は当代の聖女であり、救世騎士団の一員です。","ENG":"I am still a Saintess and a member of the Knights of Redemption.","TWN":"就算沒有這些，我也是聖女和救援騎士團的一員。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"일반인을 상대로 져서는 본보기가 되지 못하겠지요.","JPN":"一般人相手に負けては、お手本を見せることができません。","ENG":"I will not be able to set a good example by losing to civilians.","TWN":"要是輸給平凡人，就無法成為眾人的榜樣。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"응. 물론이야.","JPN":"うん。もちろん。","ENG":"Right. Of course.","TWN":"嗯，那當然。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"열심히 해. 루크레시아.","JPN":"頑張って。ルクレシア。","ENG":"I'm rooting for you, Lucrecia.","TWN":"加油，露可蕾西亞。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};